/// UUID Generator using cryptographically secure random number generation.
/// Generates RFC 4122 version 4 UUIDs without external packages.
class UuidGenerator {
  static final Random _secureRandom = Random.secure();

  /// Generates a cryptographically secure UUID v4 string.
  static String generateV4() {
    final bytes = List<int>.generate(16, (_) => _secureRandom.nextInt(256));

    // Set version to 4 (0100 in binary) — byte 6
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122 (10xx in binary) — byte 8
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatUuid(bytes);
  }

  /// Generates a time-based UUID v4 hybrid for better sortability in offline scenarios.
  /// Embeds a timestamp prefix for chronological ordering while maintaining uniqueness.
  static String generateTimeBased() {
    final now = DateTime.now().toUtc().millisecondsSinceEpoch;
    final bytes = List<int>.generate(16, (_) => _secureRandom.nextInt(256));

    // Embed timestamp in first 6 bytes (48 bits = ~8900 years from epoch)
    bytes[0] = (now >> 40) & 0xFF;
    bytes[1] = (now >> 32) & 0xFF;
    bytes[2] = (now >> 24) & 0xFF;
    bytes[3] = (now >> 16) & 0xFF;
    bytes[4] = (now >> 8) & 0xFF;
    bytes[5] = now & 0xFF;

    // Set version to 4
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatUuid(bytes);
  }

  /// Generates a namespace-based UUID using a simple hash approach.
  /// Useful for generating deterministic IDs based on a namespace and name.
  static String generateNamespaced(String namespace, String name) {
    final input = '$namespace:$name';
    final inputBytes = utf8.encode(input);

    // Simple but effective hash using secure random seed + input
    final seed = _secureRandom.nextInt(1 << 32);
    final bytes = List<int>.filled(16, 0);

    int hash = seed;
    for (int i = 0; i < inputBytes.length; i++) {
      hash = ((hash << 5) - hash + inputBytes[i]) & 0xFFFFFFFF;
      bytes[i % 16] ^= (hash >> ((i % 4) * 8)) & 0xFF;
    }

    // Additional mixing passes for better distribution
    for (int round = 0; round < 4; round++) {
      for (int i = 0; i < 16; i++) {
        hash = ((hash * 1103515245) + 12345 + bytes[i]) & 0xFFFFFFFF;
        bytes[i] = (bytes[i] ^ ((hash >> 16) & 0xFF)) & 0xFF;
      }
    }

    // Set version to 4
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatUuid(bytes);
  }

  /// Generates a short unique ID (not UUID format) for compact storage.
  static String generateShortId({int length = 12}) {
    const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    return List.generate(length, (_) => chars[_secureRandom.nextInt(chars.length)]).join();
  }

  /// Formats 16 bytes into standard UUID string format: 8-4-4-4-12
  static String _formatUuid(List<int> bytes) {
    final hex = bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
    return '${hex.substring(0, 8)}-'
        '${hex.substring(8, 12)}-'
        '${hex.substring(12, 16)}-'
        '${hex.substring(16, 20)}-'
        '${hex.substring(20, 32)}';
  }

  /// Validates whether a string is a valid UUID format.
  static bool isValidUuid(String uuid) {
    final regex = RegExp(
      r'^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$',
      caseSensitive: false,
    );
    return regex.hasMatch(uuid);
  }

  /// Extracts timestamp from a time-based UUID generated by [generateTimeBased].
  static DateTime? extractTimestamp(String uuid) {
    try {
      final hex = uuid.replaceAll('-', '');
      final timestampHex = hex.substring(0, 12);
      final milliseconds = int.parse(timestampHex, radix: 16);
      return DateTime.fromMillisecondsSinceEpoch(milliseconds, isUtc: true);
    } catch (_) {
      return null;
    }
  }
}

/// Represents an offline data entry with a generated UUID.
class OfflineRecord {
  final String id;
  final String title;
  final String content;
  final DateTime createdAt;
  final String idType;
  bool isSynced;

  OfflineRecord({
    required this.id,
    required this.title,
    required this.content,
    required this.createdAt,
    required this.idType,
    this.isSynced = false,
  });

  Map<String, dynamic> toJson() => {
        'id': id,
        'title': title,
        'content': content,
        'createdAt': createdAt.toIso8601String(),
        'idType': idType,
        'isSynced': isSynced,
      };
}

