class _OfflineRecordsTabState extends State<OfflineRecordsTab> {
  final List<OfflineRecord> _records = [];
  String _selectedIdType = 'v4';

  void _addRecord() {
    final titleController = TextEditingController();
    final contentController = TextEditingController();
    String dialogIdType = _selectedIdType;

    showDialog(
      context: context,
      builder: (context) => StatefulBuilder(
        builder: (context, setDialogState) => AlertDialog(
          title: const Text('New Offline Record'),
          content: SingleChildScrollView(
            child: Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                TextField(
                  controller: titleController,
                  decoration: const InputDecoration(
                    labelText: 'Title',
                    border: OutlineInputBorder(),
                  ),
                ),
                const SizedBox(height: 12),
                TextField(
                  controller: contentController,
                  decoration: const InputDecoration(
                    labelText: 'Content',
                    border: OutlineInputBorder(),
                  ),
                  maxLines: 3,
                ),
                const SizedBox(height: 12),
                DropdownButtonFormField<String>(
                  value: dialogIdType,
                  decoration: const InputDecoration(
                    labelText: 'ID Type',
                    border: OutlineInputBorder(),
                  ),
                  items: const [
                    DropdownMenuItem(value: 'v4', child: Text('UUID v4 (Random)')),
                    DropdownMenuItem(value: 'time', child: Text('Time-Based UUID')),
                    DropdownMenuItem(value: 'short', child: Text('Short ID')),
                  ],
                  onChanged: (v) {
                    if (v != null) {
                      setDialogState(() => dialogIdType = v);
                    }
                  },
                ),
              ],
            ),
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.pop(context),
              child: const Text('Cancel'),
            ),
            FilledButton(
              onPressed: () {
                if (titleController.text.isEmpty) return;

                String id;
                switch (dialogIdType) {
                  case 'time':
                    id = UuidGenerator.generateTimeBased();
                    break;
                  case 'short':
                    id = UuidGenerator.generateShortId();
                    break;
                  default:
                    id = UuidGenerator.generateV4();
                }

                setState(() {
                  _selectedIdType = dialogIdType;
                  _records.insert(
                    0,
                    OfflineRecord(
                      id: id,
                      title: titleController.text,
                      content: contentController.text,
                      createdAt: DateTime.now(),
                      idType: dialogIdType,
                    ),
                  );
                });

                Navigator.pop(context);
              },
              child: const Text('Create'),
            ),
          ],
        ),
      ),
    );
  }

  void _simulateSync() {
    final unsyncedCount = _records.where((r) => !r.isSynced).length;
    if (unsyncedCount == 0) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('All records are already synced!'),
          behavior: SnackBarBehavior.floating,
        ),
      );
      return;
    }

    showDialog(
      context: context,
      barrierDismissible: false,
      builder: (context) => _SyncDialog(
        recordCount: unsyncedCount,
        onComplete: () {
          setState(() {
            for (final record in _records) {
              record.isSynced = true;
            }
          });
          Navigator.pop(context);
        },
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final syncedCount = _records.where((r) => r.isSynced).length;
    final unsyncedCount = _records.length - syncedCount;

    return Column(
      children: [
        // Stats bar
        if (_records.isNotEmpty)
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
            color: theme.colorScheme.surfaceContainerHighest.withOpacity(0.3),
            child: Row(
              children: [
                _StatChip(
                  label: 'Total',
                  count: _records.length,
                  color: theme.colorScheme.primary,
