                                        label: Text(record.idType.toUpperCase()),
                                        avatar: const Icon(Icons.fingerprint, size: 16),
                                        visualDensity: VisualDensity.compact,
                                      ),
                                      Chip(
                                        label: Text(
                                          record.isSynced ? 'Synced' : 'Pending',
                                        ),
                                        avatar: Icon(
                                          record.isSynced ? Icons.check : Icons.pending,
                                          size: 16,
                                        ),
                                        backgroundColor: record.isSynced
                                            ? Colors.green.withOpacity(0.15)
                                            : Colors.orange.withOpacity(0.15),
                                        visualDensity: VisualDensity.compact,
                                      ),
                                      Chip(
                                        label: Text(
                                          '${record.createdAt.day}/${record.createdAt.month}/${record.createdAt.year} '
                                          '${record.createdAt.hour.toString().padLeft(2, '0')}:'
                                          '${record.createdAt.minute.toString().padLeft(2, '0')}',
                                        ),
                                        avatar: const Icon(Icons.schedule, size: 16),
                                        visualDensity: VisualDensity.compact,
                                      ),
                                    ],
                                  ),
                                  const SizedBox(height: 8),
                                  Row(
                                    children: [
                                      TextButton.icon(
                                        onPressed: () {
                                          Clipboard.setData(ClipboardData(text: record.id));
                                          ScaffoldMessenger.of(context).showSnackBar(
                                            SnackBar(
                                              content: Text('Copied ID: ${record.id}'),
                                              duration: const Duration(seconds: 1),
                                              behavior: SnackBarBehavior.floating,
                                            ),
                                          );
                                        },
                                        icon: const Icon(Icons.copy, size: 16),
                                        label: const Text('Copy ID'),
                                      ),
                                      TextButton.icon(
                                        onPressed: () {
                                          final json = record.toJson().toString();
                                          Clipboard.setData(ClipboardData(text: json));
                                          ScaffoldMessenger.of(context).showSnackBar(
                                            const SnackBar(
                                              content: Text('Copied JSON to clipboard'),
                                              duration: Duration(seconds: 1),
                                              behavior: SnackBarBehavior.floating,
                                            ),
                                          );
                                        },
                                        icon: const Icon(Icons.data_object, size: 16),
                                        label: const Text('Copy JSON'),
                                      ),
                                    ],
                                  ),
                                ],
                              ),
                            ),
                          ],
                        ),
                      ),
                    );
                  },
                ),
        ),
      ],
    );
  }

  @override
  Widget build2(BuildContext context) {
    return build(context);
  }
}

