class _SyncDialog extends StatefulWidget {
  final int recordCount;
  final VoidCallback onComplete;

  const _SyncDialog({required this.recordCount, required this.onComplete});

  @override
  State<_SyncDialog> createState() => _SyncDialogState();
}

class _SyncDialogState extends State<_SyncDialog> {
  double _progress = 0;
  int _currentRecord = 0;
  bool _complete = false;

  @override
  void initState() {
    super.initState();
    _startSync();
  }

  Future<void> _startSync() async {
    for (int i = 0; i < widget.recordCount; i++) {
      await Future.delayed(Duration(milliseconds: 300 + Random.secure().nextInt(400)));
      if (!mounted) return;
      setState(() {
        _currentRecord = i + 1;
        _progress = (i + 1) / widget.recordCount;
      });
    }
    if (!mounted) return;
    setState(() => _complete = true);
    await Future.delayed(const Duration(milliseconds: 500));
    if (mounted) widget.onComplete();
  }

  @override
  Widget build(BuildContext context) {
    return AlertDialog(
      title: Text(_complete ? 'Sync Complete!' : 'Syncing Records...'),
      content: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          if (!_complete) ...[
            LinearProgressIndicator(value: _progress),
            const SizedBox(height: 16),
            Text('Syncing record $_currentRecord of ${widget.recordCount}'),
          ] else ...[
            const Icon(Icons.check_circle, color: Colors.green, size: 48),
            const SizedBox(height: 12),
            Text('${widget.recordCount} records synced successfully!'),
          ],
        ],
      ),
    );
  }
}

// Override HomePage to include FAB for records tab
class _HomePageFinal extends StatefulWidget {
  const _HomePageFinal();

  @override
  State<_HomePageFinal> createState() => _HomePageFinalState();
}

class _HomePageFinalState extends State<_HomePageFinal> with SingleTickerProviderStateMixin {
  late TabController _tabController;
  final GlobalKey<_OfflineRecordsTabState> _recordsKey = GlobalKey();

  @override
  void initState() {
    super.initState();
    _tabController = TabController(length: 2, vsync: this);
    _tabController.addListener(() => setState(() {}));
  }

  @override
  void dispose() {
    _tabController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('UUID Generator'),
        centerTitle: true,
        bottom: TabBar(
          controller: _tabController,
          tabs: const [
            Tab(icon: Icon(Icons.generating_tokens), text: 'Generator'),
            Tab(icon: Icon(Icons.storage), text: 'Offline Records'),
          ],
        ),
      ),
      body: TabBarView(
        controller: _tabController,
        children: [
          const GeneratorTab(),
          OfflineRecordsTab(key: _recordsKey),
        ],
      ),
      floatingActionButton: _tabController.index == 1
          ? FloatingActionButton.extended(
              onPressed: () => _recordsKey.currentState?._addRecord(),
              icon: const Icon(Icons.add),
              label: const Text('New Record'),
            )
          : null,
    );
  }
}